package entities;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

public class Musique {
    private Integer id;
    private String genre;
    private String audio;
    private LocalDateTime updatedAt;

    // Relation many-to-many via playlist_musique (loaded by service layer).
    private List<Playlist> playlists = new ArrayList<>();

    public Musique() {
    }

    public Integer getId() {
        return id;
    }

    public void setId(Integer id) {
        this.id = id;
    }

    public String getGenre() {
        return genre;
    }

    public void setGenre(String genre) {
        this.genre = genre;
    }

    public String getAudio() {
        return audio;
    }

    public void setAudio(String audio) {
        this.audio = audio;
    }

    public LocalDateTime getUpdatedAt() {
        return updatedAt;
    }

    public void setUpdatedAt(LocalDateTime updatedAt) {
        this.updatedAt = updatedAt;
    }

    public List<Playlist> getPlaylists() {
        return playlists;
    }

    public void setPlaylists(List<Playlist> playlists) {
        this.playlists = playlists != null ? playlists : new ArrayList<>();
    }
}

package entities;

import java.time.LocalDateTime;
import java.util.ArrayList;
import java.util.List;

public class Musique extends Oeuvre {
    private String genre;
    private String audio;
    private LocalDateTime updatedAt;

    // Relation many-to-many via playlist_musique (loaded by service layer).
    private List<Playlist> playlists = new ArrayList<>();

    public Musique() {
        super();
        setClasse("musique");
    }

    public String getGenre() {
        return genre;
    }

    public void setGenre(String genre) {
        this.genre = genre;
    }

    public String getAudio() {
        return audio;
    }

    public void setAudio(String audio) {
        this.audio = audio;
    }

    public LocalDateTime getUpdatedAt() {
        return updatedAt;
    }

    public void setUpdatedAt(LocalDateTime updatedAt) {
        this.updatedAt = updatedAt;
    }

    public List<Playlist> getPlaylists() {
        return playlists;
    }

    public void setPlaylists(List<Playlist> playlists) {
        this.playlists = playlists != null ? playlists : new ArrayList<>();
    }
}

package controllers;

import entities.User;
import javafx.animation.FadeTransition;
import javafx.fxml.FXML;
import javafx.scene.Node;
import javafx.scene.control.Alert;
import javafx.scene.control.Button;
import javafx.scene.control.DatePicker;
import javafx.scene.control.Hyperlink;
import javafx.scene.control.Label;
import javafx.scene.control.PasswordField;
import javafx.scene.control.TextArea;
import javafx.scene.control.TextField;
import javafx.scene.control.Toggle;
import javafx.scene.control.ToggleButton;
import javafx.scene.control.ToggleGroup;
import javafx.scene.layout.VBox;
import javafx.stage.FileChooser;
import javafx.util.Duration;

import java.io.File;
import java.time.LocalDate;
import java.time.Period;
import java.util.regex.Pattern;

public class InscriptionController {

	private static final Pattern EMAIL_PATTERN = Pattern.compile("^[^\\s@]+@[^\\s@]+\\.[^\\s@]+$");

	@FXML private VBox stepOnePane;
	@FXML private VBox stepTwoPane;
	@FXML private VBox stepThreePane;
	@FXML private Label stepOneBadge;
	@FXML private Label stepTwoBadge;
	@FXML private Label stepThreeBadge;
	@FXML private Label specialiteLabel;
	@FXML private Label centreInteretLabel;
	@FXML private Label messageLabel;
	@FXML private Label photoPathLabel;
	@FXML private Label photoPlaceholderLabel;
	@FXML private TextField nomField;
	@FXML private TextField prenomField;
	@FXML private DatePicker dateNaissancePicker;
	@FXML private TextField phoneField;
	@FXML private TextField villeField;
	@FXML private TextField emailField;
	@FXML private PasswordField passwordField;
	@FXML private PasswordField confirmPasswordField;
	@FXML private TextField specialiteField;
	@FXML private TextField centreInteretField;
	@FXML private TextArea biographieArea;
	@FXML private ToggleGroup roleToggleGroup;
	@FXML private Button previousButton;
	@FXML private Button nextButton;
	@FXML private Button submitButton;

	private final User draftUser = new User();
	private int currentStep = 1;
	private String selectedPhotoPath;

	@FXML
	public void initialize() {
		if (roleToggleGroup.getSelectedToggle() == null && !roleToggleGroup.getToggles().isEmpty()) {
			roleToggleGroup.selectToggle(roleToggleGroup.getToggles().get(0));
		}
		roleToggleGroup.selectedToggleProperty().addListener((obs, oldV, newV) -> updateRoleHints());
		updateRoleHints();
		showStep(1, false);
	}

	@FXML
	private void onNextStep() {
		if (!validateCurrentStep()) {
			return;
		}
		showStep(Math.min(3, currentStep + 1), true);
	}

	@FXML
	private void onPreviousStep() {
		if (currentStep == 1) {
			MainFX.switchToAuthLandingView();
			return;
		}
		showStep(currentStep - 1, true);
	}

	@FXML
	private void onBackToLanding() {
		MainFX.switchToAuthLandingView();
	}

	@FXML
	private void onBrowsePhoto() {
		FileChooser chooser = new FileChooser();
		chooser.setTitle("Choisir une photo de référence");
		chooser.getExtensionFilters().addAll(
				new FileChooser.ExtensionFilter("Images", "*.png", "*.jpg", "*.jpeg", "*.gif", "*.bmp"),
				new FileChooser.ExtensionFilter("Tous les fichiers", "*.*")
		);
		File file = chooser.showOpenDialog(previousButton.getScene().getWindow());
		if (file == null) {
			return;
		}
		selectedPhotoPath = file.getAbsolutePath();
		photoPathLabel.setText(file.getName());
		photoPlaceholderLabel.setVisible(false);
		photoPlaceholderLabel.setManaged(false);
		setMessage("Photo chargée avec succès.", false);
	}

	@FXML
	private void onSubmit() {
		if (!validateCurrentStep()) {
			return;
		}
		User user = buildUser();
		Alert alert = new Alert(Alert.AlertType.INFORMATION);
		alert.setTitle("Inscription prête");
		alert.setHeaderText("Votre formulaire est bien structuré");
		alert.setContentText("Les données sont collectées correctement. Vous pouvez maintenant brancher la persistance métier.");
		alert.showAndWait();
		clearForm();
		MainFX.switchToAuthLandingView();
	}

	private boolean validateCurrentStep() {
		switch (currentStep) {
			case 1:
				return validateStepOne();
			case 2:
				return validateStepTwo();
			case 3:
				return validateStepThree();
			default:
				return true;
		}
	}

	private boolean validateStepOne() {
		if (isBlank(nomField.getText())) return failValidation("Veuillez renseigner le nom.", nomField);
		if (isBlank(prenomField.getText())) return failValidation("Veuillez renseigner le prénom.", prenomField);
		if (dateNaissancePicker.getValue() == null) return failValidation("Veuillez sélectionner une date de naissance.", dateNaissancePicker);
		if (isBlank(phoneField.getText())) return failValidation("Veuillez renseigner le numéro de téléphone.", phoneField);
		if (isBlank(villeField.getText())) return failValidation("Veuillez renseigner la ville.", villeField);
		return true;
	}

	private boolean validateStepTwo() {
		if (isBlank(emailField.getText()) || !EMAIL_PATTERN.matcher(emailField.getText().trim()).matches()) {
			return failValidation("Veuillez saisir une adresse e-mail valide.", emailField);
		}
		if (isBlank(passwordField.getText()) || passwordField.getText().length() < 8) {
			return failValidation("Le mot de passe doit contenir au moins 8 caractères.", passwordField);
		}
		if (!passwordField.getText().equals(confirmPasswordField.getText())) {
			return failValidation("La confirmation du mot de passe est incorrecte.", confirmPasswordField);
		}
		return true;
	}

	private boolean validateStepThree() {
		if (roleToggleGroup.getSelectedToggle() == null) return failValidation("Veuillez sélectionner un rôle.", null);
		if (isBlank(biographieArea.getText())) return failValidation("Veuillez ajouter une biographie.", biographieArea);
		return true;
	}

	private boolean failValidation(String message, Node focus) {
		setMessage(message, true);
		if (focus != null) focus.requestFocus();
		return false;
	}

	private void showStep(int step, boolean animate) {
		currentStep = step;
		stepOnePane.setVisible(step == 1); stepOnePane.setManaged(step == 1);
		stepTwoPane.setVisible(step == 2); stepTwoPane.setManaged(step == 2);
		stepThreePane.setVisible(step == 3); stepThreePane.setManaged(step == 3);
		if (animate) {
			fadeIn(step == 1 ? stepOnePane : step == 2 ? stepTwoPane : stepThreePane);
		}
		previousButton.setText(step == 1 ? "Retour à l'accueil" : "Précédent");
		nextButton.setVisible(step < 3); nextButton.setManaged(step < 3);
		submitButton.setVisible(step == 3); submitButton.setManaged(step == 3);
		updateStepper();
		updateRoleHints();
	}

	private void updateStepper() {
		setBadgeState(stepOneBadge, currentStep == 1, currentStep > 1);
		setBadgeState(stepTwoBadge, currentStep == 2, currentStep > 2);
		setBadgeState(stepThreeBadge, currentStep == 3, false);
	}

	private void setBadgeState(Label badge, boolean active, boolean done) {
		badge.getStyleClass().removeAll("active", "done");
		if (active) badge.getStyleClass().add("active");
		else if (done) badge.getStyleClass().add("done");
	}

	private void updateRoleHints() {
		String role = getSelectedRole();
		if ("Artiste".equalsIgnoreCase(role)) {
			specialiteLabel.setText("Spécialité artistique");
			specialiteField.setPromptText("Peinture, photographie, design...");
			centreInteretLabel.setText("Univers créatif");
			centreInteretField.setPromptText("Expo, performance, création...");
		} else if ("Admin".equalsIgnoreCase(role)) {
			specialiteLabel.setText("Domaine de gestion");
			specialiteField.setPromptText("Modération, pilotage, conformité...");
			centreInteretLabel.setText("Priorités de plateforme");
			centreInteretField.setPromptText("Utilisateurs, sécurité, qualité...");
		} else {
			specialiteLabel.setText("Spécialité");
			specialiteField.setPromptText("Dessin, illustration, curation...");
			centreInteretLabel.setText("Centre d'intérêt");
			centreInteretField.setPromptText("Art moderne, patrimoine, création...");
		}
	}

	private String getSelectedRole() {
		Toggle selected = roleToggleGroup.getSelectedToggle();
		return selected instanceof ToggleButton ? ((ToggleButton) selected).getText() : "";
	}

	private User buildUser() {
		draftUser.setNom(trim(nomField.getText()));
		draftUser.setPrenom(trim(prenomField.getText()));
		draftUser.setDateNaissance(dateNaissancePicker.getValue());
		draftUser.setNumTel(trim(phoneField.getText()));
		draftUser.setVille(trim(villeField.getText()));
		draftUser.setEmail(trim(emailField.getText()));
		draftUser.setMdp(passwordField.getText());
		draftUser.setRole(getSelectedRole());
		draftUser.setSpecialite(trim(specialiteField.getText()));
		draftUser.setCentreInteret(trim(centreInteretField.getText()));
		draftUser.setBiographie(trim(biographieArea.getText()));
		draftUser.setPhotoReferencePath(selectedPhotoPath);
		draftUser.setPhotoProfil(selectedPhotoPath);
		draftUser.setDateInscription(LocalDate.now());
		draftUser.setStatut("pending");
		draftUser.setAge(dateNaissancePicker.getValue() == null ? null : Period.between(dateNaissancePicker.getValue(), LocalDate.now()).getYears());
		return draftUser;
	}

	private void clearForm() {
		nomField.clear(); prenomField.clear(); dateNaissancePicker.setValue(null); phoneField.clear(); villeField.clear();
		emailField.clear(); passwordField.clear(); confirmPasswordField.clear(); specialiteField.clear(); centreInteretField.clear();
		biographieArea.clear(); selectedPhotoPath = null; photoPathLabel.setText("Sélectionnez une image pour votre profil.");
		photoPlaceholderLabel.setVisible(true); photoPlaceholderLabel.setManaged(true);
		if (!roleToggleGroup.getToggles().isEmpty()) roleToggleGroup.selectToggle(roleToggleGroup.getToggles().get(0));
		showStep(1, false);
	}

	private void fadeIn(Node node) {
		node.setOpacity(0.0);
		FadeTransition transition = new FadeTransition(Duration.millis(180), node);
		transition.setFromValue(0.0);
		transition.setToValue(1.0);
		transition.play();
	}

	private void setMessage(String message, boolean error) {
		messageLabel.setText(message);
		messageLabel.getStyleClass().removeAll("error", "success");
		messageLabel.getStyleClass().add(error ? "error" : "success");
	}

	private boolean isBlank(String value) { return value == null || value.trim().isEmpty(); }
	private String trim(String value) { return value == null ? null : value.trim(); }
}

package controllers;

import entities.User;
import javafx.animation.FadeTransition;
import javafx.fxml.FXML;
import javafx.scene.Node;
import javafx.scene.control.Alert;
import javafx.scene.control.Button;
import javafx.scene.control.ComboBox;
import javafx.scene.control.DatePicker;
import javafx.scene.control.Hyperlink;
import javafx.scene.control.Label;
import javafx.scene.control.PasswordField;
import javafx.scene.control.TextArea;
import javafx.scene.control.TextField;
import javafx.scene.control.Toggle;
import javafx.scene.control.ToggleButton;
import javafx.scene.control.ToggleGroup;
import javafx.scene.layout.VBox;
import javafx.stage.FileChooser;
import javafx.util.Duration;

import java.io.File;
import java.time.LocalDate;
import java.time.Period;
import java.util.regex.Pattern;

public class InscriptionController {

	private static final Pattern EMAIL_PATTERN = Pattern.compile("^[^\\s@]+@[^\\s@]+\\.[^\\s@]+$");
	private static final String ROLE_AMATEUR = "Amateur";
	private static final String ROLE_ARTISTE = "Artiste";
	private static final String ROLE_ADMIN = "Admin";
	private static final String[] CENTRES_INTERET = {
			"Peinture",
			"Sculpture",
			"Photographie",
			"Musique",
			"Lecture"
	};
	private static final String[] SPECIALITES_ARTISTE = {
			"Peintre",
			"Sculpteur",
			"Photographe",
			"Musicien",
			"Auteur"
	};

	@FXML private VBox stepOnePane;
	@FXML private VBox stepTwoPane;
	@FXML private VBox stepThreePane;
	@FXML private Label stepOneBadge;
	@FXML private Label stepTwoBadge;
	@FXML private Label stepThreeBadge;
	@FXML private VBox specialiteContainer;
	@FXML private VBox centreInteretContainer;
	@FXML private Label messageLabel;
	@FXML private Label photoPathLabel;
	@FXML private Label photoPlaceholderLabel;
	@FXML private TextField nomField;
	@FXML private TextField prenomField;
	@FXML private DatePicker dateNaissancePicker;
	@FXML private TextField phoneField;
	@FXML private TextField villeField;
	@FXML private TextField emailField;
	@FXML private PasswordField passwordField;
	@FXML private PasswordField confirmPasswordField;
	@FXML private ComboBox<String> specialiteComboBox;
	@FXML private ComboBox<String> centreInteretComboBox;
	@FXML private TextArea biographieArea;
	@FXML private ToggleGroup roleToggleGroup;
	@FXML private Button previousButton;
	@FXML private Button nextButton;
	@FXML private Button submitButton;

	private final User draftUser = new User();
	private int currentStep = 1;
	private String selectedPhotoPath;

	@FXML
	public void initialize() {
		specialiteComboBox.getItems().setAll(SPECIALITES_ARTISTE);
		centreInteretComboBox.getItems().setAll(CENTRES_INTERET);
		if (roleToggleGroup.getSelectedToggle() == null && !roleToggleGroup.getToggles().isEmpty()) {
			roleToggleGroup.selectToggle(roleToggleGroup.getToggles().get(0));
		}
		roleToggleGroup.selectedToggleProperty().addListener((obs, oldV, newV) -> updateRoleHints());
		updateRoleHints();
		showStep(1, false);
	}

	@FXML
	private void onNextStep() {
		if (!validateCurrentStep()) {
			return;
		}
		showStep(Math.min(3, currentStep + 1), true);
	}

	@FXML
	private void onPreviousStep() {
		if (currentStep == 1) {
			MainFX.switchToAuthLandingView();
			return;
		}
		showStep(currentStep - 1, true);
	}

	@FXML
	private void onBackToLanding() {
		MainFX.switchToAuthLandingView();
	}

	@FXML
	private void onBrowsePhoto() {
		FileChooser chooser = new FileChooser();
		chooser.setTitle("Choisir une photo de référence");
		chooser.getExtensionFilters().addAll(
				new FileChooser.ExtensionFilter("Images", "*.png", "*.jpg", "*.jpeg", "*.gif", "*.bmp"),
				new FileChooser.ExtensionFilter("Tous les fichiers", "*.*")
		);
		File file = chooser.showOpenDialog(previousButton.getScene().getWindow());
		if (file == null) {
			return;
		}
		selectedPhotoPath = file.getAbsolutePath();
		photoPathLabel.setText(file.getName());
		photoPlaceholderLabel.setVisible(false);
		photoPlaceholderLabel.setManaged(false);
		setMessage("Photo chargée avec succès.", false);
	}

	@FXML
	private void onSubmit() {
		if (!validateCurrentStep()) {
			return;
		}
		User user = buildUser();
		Alert alert = new Alert(Alert.AlertType.INFORMATION);
		alert.setTitle("Inscription prête");
		alert.setHeaderText("Votre formulaire est bien structuré");
		alert.setContentText("Les données sont collectées correctement. Vous pouvez maintenant brancher la persistance métier.");
		alert.showAndWait();
		clearForm();
		MainFX.switchToAuthLandingView();
	}

	private boolean validateCurrentStep() {
		switch (currentStep) {
			case 1:
				return validateStepOne();
			case 2:
				return validateStepTwo();
			case 3:
				return validateStepThree();
			default:
				return true;
		}
	}

	private boolean validateStepOne() {
		if (isBlank(nomField.getText())) return failValidation("Veuillez renseigner le nom.", nomField);
		if (isBlank(prenomField.getText())) return failValidation("Veuillez renseigner le prénom.", prenomField);
		if (dateNaissancePicker.getValue() == null) return failValidation("Veuillez sélectionner une date de naissance.", dateNaissancePicker);
		if (isBlank(phoneField.getText())) return failValidation("Veuillez renseigner le numéro de téléphone.", phoneField);
		if (isBlank(villeField.getText())) return failValidation("Veuillez renseigner la ville.", villeField);
		return true;
	}

	private boolean validateStepTwo() {
		if (isBlank(emailField.getText()) || !EMAIL_PATTERN.matcher(emailField.getText().trim()).matches()) {
			return failValidation("Veuillez saisir une adresse e-mail valide.", emailField);
		}
		if (isBlank(passwordField.getText()) || passwordField.getText().length() < 8) {
			return failValidation("Le mot de passe doit contenir au moins 8 caractères.", passwordField);
		}
		if (!passwordField.getText().equals(confirmPasswordField.getText())) {
			return failValidation("La confirmation du mot de passe est incorrecte.", confirmPasswordField);
		}
		return true;
	}

	private boolean validateStepThree() {
		if (roleToggleGroup.getSelectedToggle() == null) return failValidation("Veuillez sélectionner un rôle.", null);
		if (isBlank(biographieArea.getText())) return failValidation("Veuillez ajouter une biographie.", biographieArea);

		String role = getSelectedRole();
		if (ROLE_AMATEUR.equalsIgnoreCase(role) && centreInteretComboBox.getValue() == null) {
			return failValidation("Veuillez choisir un centre d'intérêt.", centreInteretComboBox);
		}
		if (ROLE_ARTISTE.equalsIgnoreCase(role) && specialiteComboBox.getValue() == null) {
			return failValidation("Veuillez choisir une spécialité.", specialiteComboBox);
		}
		return true;
	}

	private boolean failValidation(String message, Node focus) {
		setMessage(message, true);
		if (focus != null) focus.requestFocus();
		return false;
	}

	private void showStep(int step, boolean animate) {
		currentStep = step;
		stepOnePane.setVisible(step == 1); stepOnePane.setManaged(step == 1);
		stepTwoPane.setVisible(step == 2); stepTwoPane.setManaged(step == 2);
		stepThreePane.setVisible(step == 3); stepThreePane.setManaged(step == 3);
		if (animate) {
			fadeIn(step == 1 ? stepOnePane : step == 2 ? stepTwoPane : stepThreePane);
		}
		previousButton.setText(step == 1 ? "Retour à l'accueil" : "Précédent");
		nextButton.setVisible(step < 3); nextButton.setManaged(step < 3);
		submitButton.setVisible(step == 3); submitButton.setManaged(step == 3);
		updateStepper();
		updateRoleHints();
	}

	private void updateStepper() {
		setBadgeState(stepOneBadge, currentStep == 1, currentStep > 1);
		setBadgeState(stepTwoBadge, currentStep == 2, currentStep > 2);
		setBadgeState(stepThreeBadge, currentStep == 3, false);
	}

	private void setBadgeState(Label badge, boolean active, boolean done) {
		badge.getStyleClass().removeAll("active", "done");
		if (active) badge.getStyleClass().add("active");
		else if (done) badge.getStyleClass().add("done");
	}

	private void updateRoleHints() {
		String role = getSelectedRole();
		boolean isAmateur = ROLE_AMATEUR.equalsIgnoreCase(role);
		boolean isArtiste = ROLE_ARTISTE.equalsIgnoreCase(role);
		boolean isAdmin = ROLE_ADMIN.equalsIgnoreCase(role);

		specialiteContainer.setVisible(isArtiste);
		specialiteContainer.setManaged(isArtiste);
		centreInteretContainer.setVisible(isAmateur);
		centreInteretContainer.setManaged(isAmateur);

		if (!isArtiste) {
			specialiteComboBox.setValue(null);
		}
		if (!isAmateur) {
			centreInteretComboBox.setValue(null);
		}
		if (isAdmin) {
			specialiteComboBox.setValue(null);
			centreInteretComboBox.setValue(null);
		}
	}

	private String getSelectedRole() {
		Toggle selected = roleToggleGroup.getSelectedToggle();
		return selected instanceof ToggleButton ? ((ToggleButton) selected).getText() : "";
	}

	private User buildUser() {
		draftUser.setNom(trim(nomField.getText()));
		draftUser.setPrenom(trim(prenomField.getText()));
		draftUser.setDateNaissance(dateNaissancePicker.getValue());
		draftUser.setNumTel(trim(phoneField.getText()));
		draftUser.setVille(trim(villeField.getText()));
		draftUser.setEmail(trim(emailField.getText()));
		draftUser.setMdp(passwordField.getText());
		draftUser.setRole(getSelectedRole());
		draftUser.setSpecialite(ROLE_ARTISTE.equalsIgnoreCase(getSelectedRole()) ? trim(specialiteComboBox.getValue()) : null);
		draftUser.setCentreInteret(ROLE_AMATEUR.equalsIgnoreCase(getSelectedRole()) ? trim(centreInteretComboBox.getValue()) : null);
		draftUser.setBiographie(trim(biographieArea.getText()));
		draftUser.setPhotoReferencePath(selectedPhotoPath);
		draftUser.setPhotoProfil(selectedPhotoPath);
		draftUser.setDateInscription(LocalDate.now());
		draftUser.setStatut("pending");
		draftUser.setAge(dateNaissancePicker.getValue() == null ? null : Period.between(dateNaissancePicker.getValue(), LocalDate.now()).getYears());
		return draftUser;
	}

	private void clearForm() {
		nomField.clear(); prenomField.clear(); dateNaissancePicker.setValue(null); phoneField.clear(); villeField.clear();
		emailField.clear(); passwordField.clear(); confirmPasswordField.clear(); specialiteComboBox.setValue(null); centreInteretComboBox.setValue(null);
		biographieArea.clear(); selectedPhotoPath = null; photoPathLabel.setText("Sélectionnez une image pour votre profil.");
		photoPlaceholderLabel.setVisible(true); photoPlaceholderLabel.setManaged(true);
		if (!roleToggleGroup.getToggles().isEmpty()) roleToggleGroup.selectToggle(roleToggleGroup.getToggles().get(0));
		showStep(1, false);
	}

	private void fadeIn(Node node) {
		node.setOpacity(0.0);
		FadeTransition transition = new FadeTransition(Duration.millis(180), node);
		transition.setFromValue(0.0);
		transition.setToValue(1.0);
		transition.play();
	}

	private void setMessage(String message, boolean error) {
		messageLabel.setText(message);
		messageLabel.getStyleClass().removeAll("error", "success");
		messageLabel.getStyleClass().add(error ? "error" : "success");
	}

	private boolean isBlank(String value) { return value == null || value.trim().isEmpty(); }
	private String trim(String value) { return value == null ? null : value.trim(); }
}

package controllers.amateur;

import javafx.fxml.FXML;
import javafx.scene.control.Button;
import javafx.scene.layout.HBox;

import java.util.function.Consumer;

public class MiniAudioPlayerController {

    @FXML
    private HBox playerBar;

    @FXML
    private Button togglePlayButton;

    private Consumer<String> navigationHandler;
    private boolean playing;

    @FXML
    public void initialize() {
        playerBar.setVisible(false);
        playerBar.setManaged(false);
    }

    public void setNavigationHandler(Consumer<String> navigationHandler) {
        this.navigationHandler = navigationHandler;
    }

    public void setVisibleForRoute(String route) {
        boolean isMusicPage = "musique".equals(route);
        playerBar.setVisible(!isMusicPage);
        playerBar.setManaged(!isMusicPage);
    }

    @FXML
    private void onTogglePlay() {
        playing = !playing;
        togglePlayButton.setText(playing ? "||" : ">");
    }

    @FXML
    private void onPrevTrack() {
        // Placeholder for queue previous action.
    }

    @FXML
    private void onNextTrack() {
        // Placeholder for queue next action.
    }

    @FXML
    private void onOpenMusic() {
        if (navigationHandler != null) {
            navigationHandler.accept("musique");
        }
    }
}

package entities;

import java.time.LocalDate;
import java.time.LocalDateTime;

public class Personne {
    private Integer id;
    private String photoProfil;
    private String resetToken;
    private LocalDateTime resetTokenExpires;
    private String nom;
    private String prenom;
    private LocalDate dateNaissance;
    private String email;
    private String mdp;
    private String role;
    private String statut;
    private LocalDate dateInscription;
    private String numTel;
    private String ville;
    private String biographie;
    private String specialite;
    private String centreInteret;
    private String photoReferencePath;

    // Legacy field kept for compatibility with existing ServicePersonne.
    private Integer age;

    public Personne() {
    }

    public Personne(String nom, String prenom, Integer age) {
        this.nom = nom;
        this.prenom = prenom;
        this.age = age;
    }

    public Integer getId() {
        return id;
    }

    public void setId(Integer id) {
        this.id = id;
    }

    public String getPhotoProfil() {
        return photoProfil;
    }

    public void setPhotoProfil(String photoProfil) {
        this.photoProfil = photoProfil;
    }

    public String getResetToken() {
        return resetToken;
    }

    public void setResetToken(String resetToken) {
        this.resetToken = resetToken;
    }

    public LocalDateTime getResetTokenExpires() {
        return resetTokenExpires;
    }

    public void setResetTokenExpires(LocalDateTime resetTokenExpires) {
        this.resetTokenExpires = resetTokenExpires;
    }

    public String getNom() {
        return nom;
    }

    public void setNom(String nom) {
        this.nom = nom;
    }

    public String getPrenom() {
        return prenom;
    }

    public void setPrenom(String prenom) {
        this.prenom = prenom;
    }

    public LocalDate getDateNaissance() {
        return dateNaissance;
    }

    public void setDateNaissance(LocalDate dateNaissance) {
        this.dateNaissance = dateNaissance;
    }

    public String getEmail() {
        return email;
    }

    public void setEmail(String email) {
        this.email = email;
    }

    public String getMdp() {
        return mdp;
    }

    public void setMdp(String mdp) {
        this.mdp = mdp;
    }

    public String getRole() {
        return role;
    }

    public void setRole(String role) {
        this.role = role;
    }

    public String getStatut() {
        return statut;
    }

    public void setStatut(String statut) {
        this.statut = statut;
    }

    public LocalDate getDateInscription() {
        return dateInscription;
    }

    public void setDateInscription(LocalDate dateInscription) {
        this.dateInscription = dateInscription;
    }

    public String getNumTel() {
        return numTel;
    }

    public void setNumTel(String numTel) {
        this.numTel = numTel;
    }

    public String getVille() {
        return ville;
    }

    public void setVille(String ville) {
        this.ville = ville;
    }

    public String getBiographie() {
        return biographie;
    }

    public void setBiographie(String biographie) {
        this.biographie = biographie;
    }

    public String getSpecialite() {
        return specialite;
    }

    public void setSpecialite(String specialite) {
        this.specialite = specialite;
    }

    public String getCentreInteret() {
        return centreInteret;
    }

    public void setCentreInteret(String centreInteret) {
        this.centreInteret = centreInteret;
    }

    public String getPhotoReferencePath() {
        return photoReferencePath;
    }

    public void setPhotoReferencePath(String photoReferencePath) {
        this.photoReferencePath = photoReferencePath;
    }

    public Integer getAge() {
        return age;
    }

    public void setAge(Integer age) {
        this.age = age;
    }

    @Override
    public String toString() {
        return "Personne{" +
                "id=" + id +
                ", nom='" + nom + '\'' +
                ", prenom='" + prenom + '\'' +
                ", email='" + email + '\'' +
                ", role='" + role + '\'' +
                ", statut='" + statut + '\'' +
                '}';
    }
}

/* Base */
.auth-root {
	-fx-font-family: "Segoe UI", "Inter", "Arial";
	-fx-background-color: linear-gradient(to bottom right, #eef3ff 0%, #f7f9ff 45%, #eef2fb 100%);
}

.auth-landing-shell,
.auth-signup-shell {
	-fx-padding: 24;
}

.auth-card,
.auth-landing-card {
	-fx-background-color: rgba(255, 255, 255, 0.92);
	-fx-background-radius: 24;
	-fx-border-radius: 24;
	-fx-effect: dropshadow(gaussian, rgba(30, 41, 59, 0.15), 26, 0.18, 0, 12);
}

/* Top bar */
.auth-topbar {
	-fx-background-color: rgba(255, 255, 255, 0.88);
	-fx-border-color: rgba(99, 102, 241, 0.12);
	-fx-border-width: 0 0 1 0;
}

.auth-brand-mini,
.auth-brand {
	-fx-text-fill: #243b7a;
	-fx-font-weight: 800;
}

.auth-brand-mini {
	-fx-font-size: 19px;
}

.auth-topbar-link,
.auth-topbar-ghost,
.auth-topbar-primary {
	-fx-background-radius: 999;
	-fx-padding: 8 14;
	-fx-font-weight: 700;
	-fx-cursor: hand;
}

.auth-topbar-link {
	-fx-background-color: transparent;
	-fx-text-fill: #334155;
}

.auth-topbar-ghost {
	-fx-background-color: transparent;
	-fx-text-fill: #4f46e5;
	-fx-border-color: #c7d2fe;
	-fx-border-radius: 999;
	-fx-border-width: 1;
}

.auth-topbar-primary,
.auth-primary-button {
	-fx-background-color: linear-gradient(to right, #4338ca, #4f46e5);
	-fx-text-fill: white;
	-fx-background-radius: 14;
	-fx-font-weight: 700;
	-fx-cursor: hand;
}

.auth-topbar-primary:hover,
.auth-primary-button:hover {
	-fx-background-color: linear-gradient(to right, #3f37b8, #4338ca);
}

/* Landing hero */
.auth-landing-card {
	-fx-max-width: 1100;
}

.auth-landing-hero,
.auth-signup-hero {
	-fx-background-color: linear-gradient(to bottom right, #273c95 0%, #5164d9 60%, #7382ff 100%);
	-fx-background-radius: 24 0 0 24;
}

.auth-landing-panel,
.auth-signup-card {
	-fx-background-radius: 0 24 24 0;
}

.auth-hero-title,
.auth-title {
	-fx-text-fill: #ffffff;
	-fx-font-size: 32px;
	-fx-font-weight: 800;
	-fx-line-spacing: 0.2em;
}

.auth-hero-text,
.auth-subtitle,
.auth-panel-text,
.auth-helper-text,
.auth-message {
	-fx-font-size: 13px;
	-fx-line-spacing: 0.5em;
}

.auth-hero-text,
.auth-panel-text,
.auth-helper-text {
	-fx-text-fill: #667085;
}

.auth-panel-kicker,
.auth-section-title {
	-fx-text-fill: #4f46e5;
	-fx-font-size: 13px;
	-fx-font-weight: 800;
}

.auth-panel-title,
.auth-title {
	-fx-text-fill: #111827;
}

.auth-chip-row {
	-fx-padding: 2 0 0 0;
}

.auth-chip {
	-fx-background-color: rgba(255, 255, 255, 0.18);
	-fx-text-fill: #ffffff;
	-fx-background-radius: 999;
	-fx-padding: 7 14;
	-fx-font-size: 12px;
	-fx-font-weight: 700;
}

/* Form */
.auth-stepper {
	-fx-padding: 2 0 4 0;
}

.auth-step-badge {
	-fx-min-width: 34;
	-fx-min-height: 34;
	-fx-alignment: center;
	-fx-background-color: #e5e7eb;
	-fx-text-fill: #6b7280;
	-fx-font-weight: 800;
	-fx-background-radius: 999;
}

.auth-step-badge.active {
	-fx-background-color: #4f46e5;
	-fx-text-fill: white;
}

.auth-step-badge.done {
	-fx-background-color: #22c55e;
	-fx-text-fill: white;
}

.auth-field-label {
	-fx-text-fill: #334155;
	-fx-font-size: 13px;
	-fx-font-weight: 700;
}

.auth-input {
	-fx-background-color: white;
	-fx-background-radius: 22;
	-fx-border-radius: 22;
	-fx-border-color: #cbd5e1;
	-fx-border-width: 1;
	-fx-padding: 11 14;
	-fx-font-size: 14px;
}

.auth-input:focused {
	-fx-border-color: #4f46e5;
	-fx-effect: dropshadow(gaussian, rgba(79, 70, 229, 0.18), 14, 0.15, 0, 0);
}

.auth-textarea {
	-fx-pref-row-count: 4;
}

.auth-role-toggle,
.auth-secondary-button,
.auth-link-button {
	-fx-cursor: hand;
}

.auth-role-toggle {
	-fx-background-color: #edf2ff;
	-fx-text-fill: #334155;
	-fx-background-radius: 999;
	-fx-border-radius: 999;
	-fx-border-color: transparent;
	-fx-font-weight: 700;
	-fx-padding: 10 16;
}

.auth-role-toggle:selected {
	-fx-background-color: #4f46e5;
	-fx-text-fill: white;
}

.auth-secondary-button {
	-fx-background-color: transparent;
	-fx-text-fill: #334155;
	-fx-font-weight: 700;
	-fx-background-radius: 14;
	-fx-border-color: #c7d2fe;
	-fx-border-width: 1.2;
	-fx-border-radius: 14;
	-fx-padding: 12 18;
}

.auth-secondary-button:hover,
.auth-topbar-link:hover,
.auth-link-button:hover {
	-fx-background-color: #eef2ff;
}

.auth-link-button {
	-fx-background-color: transparent;
	-fx-text-fill: #4f46e5;
	-fx-font-weight: 700;
	-fx-padding: 0;
}

.auth-photo-preview {
	-fx-min-width: 150;
	-fx-min-height: 150;
	-fx-background-color: #cbd5e1;
	-fx-background-radius: 18;
	-fx-border-radius: 18;
	-fx-border-color: rgba(255,255,255,0.55);
	-fx-border-width: 1;
}

.auth-photo-placeholder {
	-fx-text-fill: white;
	-fx-font-weight: 700;
	-fx-opacity: 0.85;
}

.auth-message {
	-fx-min-height: 20;
}

.auth-message.error {
	-fx-text-fill: #dc2626;
}

.auth-message.success {
	-fx-text-fill: #16a34a;
}

.auth-signup-card {
	-fx-background-color: rgba(255, 255, 255, 0.96);
}

.auth-scroll,
.auth-scroll > .viewport {
	-fx-background-color: transparent;
}

